SELECT c.name AS customer, '收款单' AS type, f.name AS frame, i.time AS time, i.number AS number, 0 AS increaseAccountsReceivable, 0 AS increaseAdvanceReceipts, c.balance AS balance, i.data AS data FROM imy i JOIN customer c ON i.customer = c.id JOIN frame f ON i.frame = f.id WHERE 1=1
AND i.customer = #{query.customer}
AND c.category = #{query.category}
AND i.time >= #{query.startTime}
AND i.time <= #{query.endTime}

